// event.sceneViewPanelCreated

import { fetchJsonFromUrl, getUrlQueryParams, getI18nText } from "./commonFunc";
import { EXAMPLE_SCENES } from "./exampleJson";
import { globalManager, modelDialogTools, globalTools, globalConfig } from "./globalConfig";
import { sceneUtils } from "./sceneUtils";

export class ExampleUtils {
    constructor() {
        window.addEventListener('event.sceneViewPanelCreated', this.onSceneViewPanelCreated.bind(this));
    }

    async onSceneViewPanelCreated() {
        const urlParams = getUrlQueryParams();
        if (urlParams.scene) {
            const exampleScene = EXAMPLE_SCENES[urlParams.scene as keyof typeof EXAMPLE_SCENES];
            while (!globalConfig.confirmNoticeMessageDialog) {
                await new Promise(resolve => setTimeout(resolve, 100));
            }
            if (exampleScene) {
                console.log('加载示例场景:', exampleScene);
                modelDialogTools.showLoadingInfoModal(getI18nText('loadingMessage.loadingExampleScene'));
                const sceneData = await fetchJsonFromUrl(exampleScene.sceneList[0]);
                if (!sceneData || !sceneData.scenes || sceneData.scenes.length == 0) {
                    modelDialogTools.showLoadingInfoModal(getI18nText('loadingMessage.exampleSceneNotExists'));
                    setTimeout(() => {
                        modelDialogTools.closeLoadingInfoModal();
                    }, 1000 * 3);
                    return;
                }
                if (exampleScene.sceneList.length > 0) { // 单场景示例
                    (async () => {
                        const sceneData = await fetchJsonFromUrl(exampleScene.sceneList[0]);
                        if (sceneData && sceneData.scenes && sceneData.scenes.length > 0) {
                            console.log('sceneData:', sceneData);
                            if (sceneData.scenes.length == 1) {
                                const newSceneData = Object.assign(
                                    {},
                                    sceneData.scenes[0],
                                    {
                                        camera: sceneData.camera,
                                        totalFrames: sceneData.totalFrames,
                                    }
                                );
                                globalTools.mainViewTools?.loadSceneByJson(true, newSceneData);
                            } else {
                                const result = await sceneUtils.setMultiWindow(); // 创建新面板
                                globalTools.toolbarNavTools?.setSceneWindowSingle(false);
                                console.log('[ExampleUtils] 设置多视窗窗口', result);
                                if (result) {
                                    console.log('[ExampleUtils] 多视窗场景示例数据:', sceneData.scenes[1]);
                                    const newSceneData = Object.assign(
                                        {},
                                        sceneData.scenes[0],
                                        {
                                            camera: sceneData.camera,
                                            totalFrames: sceneData.totalFrames,
                                        }
                                    );
                                    const newSceneData2 = Object.assign(
                                        {},
                                        sceneData.scenes[1],
                                        {
                                            camera: sceneData.camera,
                                            totalFrames: sceneData.totalFrames,
                                        }
                                    );
                                    globalTools.mainViewTools?.loadSceneByJson(true, newSceneData);
                                    globalTools.mainViewTools?.loadSceneByJson(false, newSceneData2);
                                }
                            }
                        } else {
                            modelDialogTools.showLoadingInfoModal(getI18nText('loadingMessage.exampleSceneNotExists'));
                            setTimeout(() => {
                                modelDialogTools.closeLoadingInfoModal();
                            }, 1000 * 3);
                            return;
                        }
                    })();
                } else {
                    modelDialogTools.showLoadingInfoModal(getI18nText('loadingMessage.exampleSceneNotExists'));
                    setTimeout(() => {
                        modelDialogTools.closeLoadingInfoModal();
                    }, 1000 * 3);
                    return;
                }
            } else {
                modelDialogTools.showLoadingInfoModal('示例场景不存在，请选择其他示例场景');
                setTimeout(() => {
                    modelDialogTools.closeLoadingInfoModal();
                }, 1000 * 3);
                return;
            }
        } else {
            console.log('不需要生成示例数据');
        }
    }
}

